<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <tg-list :IsShowAction="true" ModuleName="Billing" SubModuleCode="" :LegendArray="LegendArray"
            :RenderRowActionMethod="renderActions" v-on:ActionButtonClick="actionButtonClick" :widgets="[]"
            IdentityColumn="SERVICEID" :listType="['List']" :ListData="ListingData" :HeaderData="Headers"
            :isShowHeaderText="false" :HeaderText="!isBillingType ? $t('BillingCondition'): $t('BillingService')" :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords"
            :SearchFields="leftSearchFields" 
            :ListDataCallBackFunction="FetchData" :showCheckBox="true" :SortExp="SortExp" :SortBy="SortBy"
            :NorecordfoundText="$t('NoRecordfound')" v-on:LeftsearchButtonClick="leftCommonSearch"
            v-on:PagerButtonClick="pagerMethod" v-on:HeaderButtonClick="commonHeaderButtonClick"
            v-on:SortdataButtonClick="sortdata" :routeInfo="$router">
            <!-- IsSearchFieldsOnTop="true" SearchPosition="top" -->
            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME == 'SERVICENAME'">
                    <td>
                        <a @click="EditRecord(data.row)" class="text-primary">
                            {{ data.row.SERVICENAME }}
                        </a>
                    </td>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'MODIFIED_AT'">
                    <td class="text-center single-action tourguide_a" v-if="data.row.MODIFIED_AT">
                        {{ $options.filters.formatDate(toUserDateTime(data.row.MODIFIED_AT,timeZone)) }}
                    </td>
                    <td class="text-center single-action tourguide_a" v-else>--</td>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'BILLING_CONFIG_NAME'">
                    <span>
                        {{ data.row.BILLING_CONFIG_NAME ? data.row.BILLING_CONFIG_NAME : '--' }}
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'STATUS'">

                    <div v-if="data.row.SCOUNT == 0">
                        <div class="cstm-drop-btn">
                            <select v-model="data.row.STATUSID" @change="UpdataStatus(data.row.STATUSID, data.row.SERVICEID);" :class="data.row.STATUSID == 1001 ? 'ddlupdatestatus w-80 btn-success' : 'ddlupdatestatus w-80 btn-danger'">
                                <option value="1001" selected="selected">{{ $t("Active") }}</option>
                                <option value="1002">{{ $t("Inactive") }}</option>
                            </select>
                        </div>
                    </div>
                    <div v-else class="active-disabled w-80">
                        <span v-bind:class="getStatusClassList(data.row.STATUS)" v-if="data.row.STATUS == 'Active'">
                            {{ data.row.STATUS }}
                        </span>
                        <span v-bind:class="getStatusClassList(data.row.STATUS)" v-if="data.row.STATUS == 'Inactive'">
                            {{ data.row.STATUS }}
                        </span>
                    </div>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'SCOUNT'">
                    <span v-if="data.row.CATEGORY != 'Global'">
                         <a href="javascript:;" :class="{ 'text-dark viewnotes': true,'disabled' :  data.row.SCOUNT == 0 ? true: false}"
                        v-on:click="OpenBillingRuleListing(data.row)"><i aria-hidden="true" class="fa fa-file-text-o"></i><span class="noti-circle noti-orange">{{
                                data.row[data.column.COLUMN_NAME] }}</span></a>
                    </span>
                    <span v-else>--</span>
                </template>
            </template>
        </tg-list>
        <div name="modal" v-if="isCloneModel">
            <loader :is-visible="isLoading" />
            <div class="modal my-popups right fade d-block" :class="{ show: isShown }">
                <div role="document" class="modal-dialog" style="max-width: 1100px !important;">
                    <div class="modal-content">
                        <div
                            class="modal-header theme-primary partition-full d-flex justify-content-between align-items-center">
                            <h5 class="modal-title">
                                {{ (isBillingType ? $t('CloneService') : $t('CloneCondition')) + ': ' + templateName }}
                            </h5>
                            <button type="button" class="close" @click="CloseCloneModel">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                        </div>
                        <div class="modal-body">
                            <dynamic-form lang="en" ref="validateClone" :buttons="buttons" :schema="FormSchema"
                                :mandatorytext="$t('MandatoryString')" />
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <ServiceHistory v-if="IsHistory" :ServiceId="ServiceId" :isBillingType="isBillingType"></ServiceHistory>
        <ModalAddBillingRule v-if="isModalAddRule" :serviceDetailForBillingRule="serviceDetailForBillingRule"
            :reqFrom="reqFrom" :configurationId="configurationId" :conditionId="conditionId" :nodeName="nodeName">
        </ModalAddBillingRule>
        <ManageBillingRuleForm v-if="isManageBillingRuleForm" :reqFrom="reqFrom" :category="category"
             :configurationId="configurationId" :conditionId="conditionId" :nodeName="nodeName"
            :setupId="setupId" :categoryId="categoryId"  :mode="mode" :isBillingType="isBillingType" :sCount="sCount">
        </ManageBillingRuleForm>

        <div name="modal" v-if="isOpenRuleList">
            <div class="modal my-popups right fade d-block" :class="{ show: isShownMapBillingRule }">
                <loader :is-visible="isRuleListLoading"></loader>
                    <div role="document" class="modal-dialog" style="max-width: 1100px !important;">
                        <div class="modal-content">
                            <div class="modal-header">
                                <h4 class="modal-title">{{ $t('MappedBillingRule') }}</h4>

                                <button type="button" class="close" v-on:click="CloseList">
                                    <em class="fa fa-times" aria-hidden="true"></em>
                                </button>

                            </div>

                            <div class="modal-body">
                                  <div class="listing" v-if="RuleListingData && RuleListingData.length">
                                    <div class="table-responsive table-fix-header mt-2 px-0">
                                            <table id="example" class="table table-bordered table-sm mb-0 custom-table">
                                                <thead class="thead-bg">
                                                    <tr>
                                                        <th class="font-weight-500">
                                                            {{ $t('Billing Rule Name') }}
                                                        </th>
                                                        <th class="font-weight-500">
                                                            {{ $t('ServiceName') }}
                                                        </th>
                                                    </tr>
                                                </thead>

                                                <tbody>
                                                    <tr v-for="(item, index) in RuleListingData" :key="index">
                                                        <td v-if="isBillingType">
                                                             <a :href="OpenRuleDetail(item)"  class="rule-link"
                                                            title="Click here to view billing rule"
                                                            v-html="truncateText(item.RULE_NAME, 60)"><i aria-hidden="true"></i></a>
                                                        </td>
                                                        <td v-else>
                                                            {{ item.BILLING_CONFIG_NAME }}
                                                        </td>
                                                        <td>
                                                            {{ item.SERVICE_NAME }}
                                                        </td>

                                                    </tr>
                                                </tbody>
                                            </table>
                                        
                                    </div>
                                </div>
                            </div>

                            <div class="modal-footer">
                                <button @click="CloseList" class="btn btn-danger">
                                    <em class="fa fa-times pr-2" aria-hidden="true"></em> {{ $t('Cancel') }}
                                </button>
                            </div>
                        </div>
                    </div>
            </div>
        </div>
    </section>
</template>

<script>
import Schema from "./BillingServiceSchema";
import DataServices from "@/services/DataService";
import  { locateBillingService } from '../../services/locateBillingService'
import ServiceHistory from './ServiceHistory.vue';
import ModalAddBillingRule from "../../components/Modals/modalAddBillingRule.vue";
import ManageBillingRuleForm from "../../components/Modals/manageBillingRuleFormForUsic.vue";
export default {
    components: { ServiceHistory, ModalAddBillingRule,ManageBillingRuleForm },
    data() {
        return {
            reqFrom: 'fromBillingService',
            isCloneModel: false,
            templateName: '',
            isModalAddRule: false,
            isLoading: false,
            conditionId: 0,
            StatusListForListing: [{ STATUS: 'Active', STATUS_ID: 1001, STATUS_COLOR: "#ffffff", STATUS_BG_COLOR: "#28a745" },
                                   { STATUS: 'Inactive', STATUS_ID: 1002, STATUS_COLOR: "#ffffff", STATUS_BG_COLOR: "#d72435" }],
            Headers: [{
                "COLUMN_NAME": "SERVICENAME",
                "DATA_TYPE": "text",
                "SORTABLE": true,
                "VISIBLE": true,
                "DISPLAY_NAME": this.$t('ConditionName'),
                "DISPLAY_ORDER": 1,
                settings: {
                    isInSlot: true
                }

            },
            {
                "COLUMN_NAME": "SCOUNT",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": this.$t('BillingRule') +' '+ this.$t('Count'),
                "DISPLAY_ORDER": 2,
                settings: {
                    isInSlot: true
                }

            },
            {
                "COLUMN_NAME": "CATEGORY",
                "DATA_TYPE": "text",
                "SORTABLE": true,
                "VISIBLE": true,
                "DISPLAY_NAME": this.$t('CategoryName'),
                "DISPLAY_ORDER": 3
            },
            {
                "COLUMN_NAME": "SETUP",
                "DATA_TYPE": "text",
                "SORTABLE": true,
                "VISIBLE": true,
                "DISPLAY_NAME": this.$t('SetupName'),
                "DISPLAY_ORDER": 4,
            },
            {
                "COLUMN_NAME": "CREATED_BY",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": this.$t('CreatedBy'),
                "DISPLAY_ORDER": 6,
            },
            {
                "COLUMN_NAME": "MODIFIED_AT",
                "DATA_TYPE": "Date",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": this.$t('LastUpdatedDate'),
                "DISPLAY_ORDER": 5,
                settings: {
                    isInSlot: true
                }
            },
            {
                "COLUMN_NAME": "UPDATEDBY",
                "DATA_TYPE": "text",
                "SORTABLE": false,
                "VISIBLE": true,
                "DISPLAY_NAME": this.$t('LastUpdatedBy'),
                "DISPLAY_ORDER": 6,
            },
            {
                "COLUMN_NAME": "STATUS",
                "DATA_TYPE": "Date",
                "SORTABLE": true,
                "VISIBLE": true,
                "DISPLAY_NAME": this.$t('Status'),
                "DISPLAY_ORDER": 7,
                settings: {
                    isInSlot: true
                }
            }
            ],
            leftSearchFields: [
                {
                    fieldName: '',
                    fieldType: "text",
                    fieldIcon: "fa fa-wrench",
                    fieldSearchConditionName: ['SERVICE_NAME'],
                    paramName: "SERVICE_NAME",
                    isSearch: false,
                    value: "",
                    listOptions: []
                },
                {
                    fieldName: 'CategoryName',
                    fieldType: "ddl-check",
                    fieldIcon: "fa fa-list",
                    fieldSearchConditionName: ['CATEGORY_NAME'],
                    paramName: "CATEGORY_NAME",
                    isSearch: false,
                    value: "",
                    listOptions: []
                },
                {
                    fieldName: 'CreatedBy',
                    fieldType: "ddl-check",
                    fieldIcon: "fa fa-user",
                    fieldSearchConditionName: ['CREATED_BY'],
                    paramName: "CREATED_BY",
                    isSearch: false,
                    value: "",
                    listOptions: []
                }
            ],
            FormSchema: [{
                layoutType: 'single',
                Data: [
                    {
                        astype: 'TextField',
                        label: this.$t('ConditionName'),
                        name: 'ServiceName',
                        value: "",
                        placeholder: '',
                        validationRules: {
                            required: true
                        },
                        disabled: false,
                    }
                ]
            }],
            buttons: [
                {
                    type: 'submit',
                    class: 'btn btn-success',
                    text: "<i class='fa fa-save pr-2'></i>" + this.$t('Save'),
                    onClick: this.CreateClone
                },
                {
                    type: 'button',
                    class: 'btn btn-danger',
                    text: "<i class='fa fa-close pr-2'></i>" + this.$t('Cancel'),
                    onClick: this.CloseCloneModel
                }
            ],
            CloneItem: [],
            SortBy: '',
            SortExp: '',
            noRecords: '',
            PageSize: "10",
            PageNumber: "1",
            TotalRecords: 0,
            CurrentPage: 1,
            TotalPages: 0,
            searchCondition: '',
            ListingData: [],
            listheaderbuttons: Schema.buttons,
            listActions: Schema.listActions,
            UserType: '',
            UserId: '',
            setupId: 32,
            IsHistory: false,
            ServiceId: '',
            isOpenRuleList: false,
            RuleListingData: [],
            isRuleListLoading: false,
            ruleListCacheByServiceId: {},
            isBillingType:false,
            LegendArray: [
                {
                class: "legend-Progress colorboxsquare",
                text: this.$t('Global'),
                }
            ],
            isManageBillingRuleForm:false,
            timeZone:'',
            searchByServiceName:'',
            searchByCategoryName:'',
            searchByCreatedBy:'',
            isShownMapBillingRule:false,
            isShown: false
        }
    },
    created: async function () {
        var vm = this;
        this.timeZone =this.GetUserInfo.TimeZone;
        this.isBillingType = localStorage.getItem("billingType") === "USIC";
        this.leftSearchFields[0].fieldName = this.isBillingType ? this.$t('Service Name') : this.$t('Condition Name');
        this.Headers[0].DISPLAY_NAME = this.isBillingType ? this.$t('ServiceName') : this.$t('ConditionName');
        this.BindCategoryDropdDownList();
        this.BindCreatedByListByTable();
        this.listheaderbuttons[0].title = this.isBillingType ? 'Add Service' : 'AddCondition';
        this.FormSchema[0].Data[0].label = this.isBillingType ? this.$t('ServiceName') : this.$t('ConditionName');
        await vm.FetchData();
        vm.UserId = this.GetUserInfo.ID;
        vm.UserType = vm.GetUserInfo.UserType;

    },
    methods: {
        BindCategoryDropdDownList: async function () {
            var vm = this;
            await DataServices.BindCategoryDropdDownList().then((response) => {
                if (response.data != '' && response.data != null) {                
                    const targetField = vm.leftSearchFields.find(field => field.fieldName === 'CategoryName'); // Find the field by name
                    if (targetField) {
                        targetField.listOptions = response.data.map(element => ({ name:  element.CATEGORY_NAME, value: element.CATEGORY_ID }));
                    }
                } 
            });
        },
        BindCreatedByListByTable: async function () {
            var vm = this;
             var url = `tableName=TALYGEN_BE_SERVICE_MASTER`;
            await DataServices.BindCreatedByListByTable(url).then((response) => {
                if (response.data != '' && response.data != null) {                
                    const targetField = vm.leftSearchFields.find(field => field.fieldName === 'CreatedBy'); // Find the field by name
                    if (targetField) {
                        targetField.listOptions = response.data.map(element => ({ name:  element.USER_NAME, value: element.USER_ID }));
                    }
                } 
            });
        },
        OpenRuleDetail: function (data) {
            var vm = this;
            if(this.isBillingType){
                return this.$router.resolve({
                        name: 'ViewConfiguration',
                        params: { id: data.CONFIGURATION_ID,serviceId:data.SERVICE_ID,mode :'View' }
                    }).href;
            }
            else{
                 return this.$router.resolve({
                        name: 'ViewConfiguration',
                        params: { id: data.CONFIGURATION_ID,serviceId:data.BILLING_SERVICE_ID,mode :'View' }
                    }).href;
            }
        },
        EditRecord(item) {
            var vm = this;
            // PRIVILEGE-CHECK: BillingService / Update (added for Edit modal)
            var param = 'controller=BillingService&action=Update';
            DataServices.CheckPrivilege(param).then(function (response) {
                    if (response.data) {
                        vm.category = item.CATEGORY;
                        vm.conditionId = item.SERVICEID;
                        vm.nodeName = item.IS_LEAF_NODE;
                        vm.configurationId = item.CONFIGURATION_ID;
                        vm.setupId = item.SETUP_ID;
                        vm.categoryId= item.CATEGORYID;
                        vm.sCount= item.SCOUNT;
                        vm.reqFrom = 'fromBillingService';
                        vm.workCode = item.WORK_CODE || null;
                        vm.serviceFlag = item.SERVICE_FLAG ;
                        vm.isLeafNode = item.IS_LEAF_NODE ;
                        if(vm.isBillingType)
                        {
                        vm.isManageBillingRuleForm = true;
                        }
                        else{
                            vm.isModalAddRule = true;
                        }
                    }
                    else {
                        vm.ShowAlert(vm.$t("NotAuthorizedSection"), 'failure', true, vm.$t('Alert'));
                    }
            })
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                this.searchCondition = value.searchCondition;
                let str = value.searchConditionJson;
                const params = new URLSearchParams(str);
                this.searchByServiceName = params.get('SERVICE_NAME') || '';
                this.searchByCategoryName = params.get('CATEGORY_NAME') || '';
                this.searchByCreatedBy = params.get('CREATED_BY') || '';
            }
            else {
                this.searchByCreatedBy = "";
                this.searchByServiceName = "";
                this.searchByCategoryName = "";
            }
            this.FetchData();
        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "AddService":
                    this.AddService();
                    break;
                case "Delete":
                    this.DeleteData();
                    break;
            }
        },
        AddService: function (item) {
            var vm = this;
            // PRIVILEGE-CHECK: BillingService / Add (added for Add Service/Condition modal)
            var param = 'controller=BillingService&action=Add';
                DataServices.CheckPrivilege(param).then(function (response) {
                    if (response.data) {
                        vm.serviceDetailForBillingRule = item;
                        vm.conditionId = 0;
                        vm.reqFrom = 'addBillingService';
                        if(vm.isBillingType)
                        {
                        vm.isManageBillingRuleForm = true;
                        }
                        else{
                            vm.isModalAddRule = true;
                        }
                    }
                    else {
                        vm.ShowAlert(vm.$t("NotAuthorizedSection"), 'failure', true, vm.$t('Alert'));
                    }
            })
        },
        DeleteData: function () {
            var vm = this;
            var val = "";
            debugger;
            $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
                if (val.length > 0)
                    val += ',';
                val += $(this).val();
            });
            if (val.length > 0) {
                // PRIVILEGE-CHECK: BillingService / Delete (added)
                var privilegeParams = `controller=BillingService&action=Delete`;
                DataServices.CheckPrivilege(privilegeParams).then(function (response) {
                    if (!response.data) {
                        vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                        return;
                    }
                    if(vm.isBillingType){
                        vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("Service")), function () {
                            let url = `ids=${val}&tableName=TALYGEN_BE_SERVICE_MASTER&primaryKey=SERVICE_ID`;
                            DataServices.Delete(url).then(response => {
                                if (response.data) {
                                    vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('Service')]), "Success", true, vm.$t('Alert'));
                                } else {
                                    vm.ShowAlert(vm.$t('DeletedError', [vm.$t('Service')]), "failure", true, vm.$t('Alert'));
                                }
                                vm.FetchData();
                            });
                        });
                    }
                    else{
                        vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("Condition")), function () {
                            let url = `ids=${val}&tableName=TALYGEN_BE_SERVICE_MASTER&primaryKey=SERVICE_ID`;
                            DataServices.Delete(url).then(response => {
                                if (response.data) {
                                    vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('Condition')]), "Success", true, vm.$t('Alert'));
                                } else {
                                    vm.ShowAlert(vm.$t('DeletedError', [vm.$t('Condition')]), "failure", true, vm.$t('Alert'));
                                }
                                vm.FetchData();
                            });
                        });
                    }
                });
            }
        },
        sortdata: function (sortBy) {
            this.SortBy = sortBy;
            if (this.SortBy == "MODIFIED_AT") {
                this.SortBy = "LASTUPDATEDDATE"
            }
            if (this.SortBy == "UPDATEDBY") {
                this.SortBy = "LASTUPDATEDBY"
            }
            var sortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                sortExp = 'DESC';
            }
            this.SortExp = sortExp;
            this.SortBy = sortBy;
            this.SortExp = sortExp;
            this.PageNumber = 1;
            this.FetchData();
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        getStatusClassList: function (status) {
            var returnClass = '';
            switch (status) {
                case 'Active':
                    returnClass = 'px-2 text-center text-white d-block bg-success';
                    break;
                case 'Inactive':
                    returnClass = 'px-2 text-center text-white d-block bg-danger';
                    break;
                default:
                    returnClass = '';
            }
            return returnClass;
        },
        getStatusClass: function (status) {
            var returnClass = "";
            switch (status) {
                case "Active":
                    returnClass = "px-2 text-center bg-success text-white d-block";
                    break;
                case "Inactive":
                    returnClass = "px-2 text-center bg-danger text-white d-block";
                    break;
                default:
                    returnClass = "";
            }
            return returnClass;
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = {
                    ...actionItem
                };
                switch (action.title) {
                    case 'Reason':
                        action.isVisible = true;
                        break;
                    case 'Resource Impact':
                        action.isVisible = true;
                        break;
                    case 'Status History':
                        action.isVisible = true;
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        OpenHistoryModal: function (item) {
            var vm = this;
            vm.ServiceId = item.SERVICEID;
            // PRIVILEGE-CHECK: BillingService / GetServiceHistory (added for History modal)
            var privilegeParams = `controller=BillingService&action=GetServiceHistory`;
            DataServices.CheckPrivilege(privilegeParams).then(function (response) {
                if (response.data) {
                    vm.IsHistory = true;
                }
                else {
                    vm.ShowAlert(vm.$t('UnAuthorized'), "failure", vm.$t('Alert'));
                    return false;
                }
            });
        },
        actionButtonClick: function (callbackfunction, item, index, event) {
            switch (callbackfunction) {
                case "ViewHistory":
                    this.OpenHistoryModal(item);
                    break;
                case "CloneService":
                    this.CloneService(item);
                    break;
            }
        },
        OpenBillingRuleListing: async function(item) {
            const vm = this;
            if (vm.isRuleListLoading) return;
            const serviceId = item?.SERVICEID > 0 ? item.SERVICEID : 0;
            vm.isOpenRuleList = true;
            vm.RuleListingData = [];
            vm.isShownMapBillingRule = false;
            vm.$nextTick(() => {
                setTimeout(() => {
                    vm.isShownMapBillingRule = true;
                }, 10);
            });

            // Use cached data if available to avoid repeated slow calls.
            if (vm.ruleListCacheByServiceId[serviceId]) {
                vm.RuleListingData = vm.ruleListCacheByServiceId[serviceId];
                return;
            }

            vm.isRuleListLoading = true;
            try {
                const url = `serviceId=${serviceId}`;
                const response = await DataServices.GetRuleListingByServiceId(url);
                const raw = response?.data;
                const list = raw && raw !== "[]" ? JSON.parse(raw) : [];
                vm.RuleListingData = Array.isArray(list) ? list : [];
                vm.ruleListCacheByServiceId[serviceId] = vm.RuleListingData;
            } catch (e) {
                vm.RuleListingData = [];
            } finally {
                vm.isRuleListLoading = false;
            }
        },
        CloseList: function () {
            var vueObj = this;
            vueObj.isOpenRuleList = false;
            vueObj.$nextTick(() => {
                setTimeout(() => {
                    vueObj.isShownMapBillingRule = false;  // adds .show ? triggers transform transition
                }, 50);
            });
        },
        CloneService(item) {
            var vm = this;
            vm.templateName = item.SERVICENAME;
            // PRIVILEGE-CHECK: BillingService / CloneService (added for Clone modal)
            var privilegeParams = `controller=BillingService&action=CloneService`;
            DataServices.CheckPrivilege(privilegeParams).then(function (response) {
                if (response.data) {
                    vm.isCloneModel = true;
                    vm.$nextTick(() => {
                        setTimeout(() => {
                            vm.isShown = true;  // adds .show ? triggers transform transition
                        }, 50);
                    });
                    vm.CloneItem = item;
                }
                else {
                    vm.ShowAlert(vm.$t('UnAuthorized'), "failure", vm.$t('Alert'));
                    return false;
                }
            });
        },
        CloseCloneModel() {
            var vueObj = this;
            vueObj.isCloneModel = false;
            vueObj.$nextTick(() => {
                setTimeout(() => {
                    vueObj.isShown = false;  // adds .show ? triggers transform transition
                }, 50);
            });
        },
        FetchData: async function () {
            var vm = this;
            const url = `isIncludeGlobal=true&serviceName=${vm.searchByServiceName}&categoryId=${vm.searchByCategoryName}&createdBy=${vm.searchByCreatedBy}&pageSize=${vm.PageSize}&pageNumber=${vm.PageNumber}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&setupId=${vm.setupId}`;
            try {
                const response = await DataServices.GetBillServiceListing(url);
                if (response.data && response.data.length > 0) {
                    vm.ListingData = response.data;
                    vm.ListingData = response.data.map(row => ({
                        ...row,
                        MODIFIED_AT: row.MODIFIED_AT ? new Date(row.MODIFIED_AT) : null,
                        isCheckBoxDisabled: row.SCOUNT !== 0,
                        additionalClass: row.IS_GLOBAL ? "low-bar" : ""
                    }));
                    vm.listheaderbuttons[1].isdisabled = true;
                    vm.TotalRecords = response.data[0].TOTALRECORDS;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;
                    vm.noRecords = false;

                } else {
                    vm.ListingData = [];
                    vm.TotalRecords = 0;
                    vm.noRecords = true;
                }

            } catch (error) {
                console.log("Error fetching data:", error);
            }
        },
        CreateClone: function () {
            var vm = this;
            var cloneName = vm.$refs.validateClone.getPropertyValue("ServiceName", "value");
            var serviceId = vm.CloneItem.SERVICEID;
            var url = `serviceId=${serviceId}&serviceName=${cloneName}`;
            DataServices.CloneBillingService(url).then((response) => {
                if (response.data.status == "Success") {
                    if(this.isBillingType){
                        this.ShowAlert(this.$t('SuccessClone', [this.$t('Service')]), "Success", true, this.$t('Alert'));
                    }
                    else{
                        this.ShowAlert(this.$t('SuccessClone', [this.$t('Condiiton')]), "Success", true, this.$t('Alert'));
                    }
                    vm.$refs.validateClone.updateProperty('ServiceName', 'value', '');
                    vm.CloseCloneModel();
                    vm.FetchData();
                }
                else {
                    this.ShowAlert(this.$t('ErrorWhileSaving', [this.$t('Service')]), "danger", true, this.$t('Alert'));
                }
            });
        },
        UpdataStatus(StatusID, ID) {
            var vm = this;
            // PRIVILEGE-CHECK: BillingService / UpdateStatus (added)
            var privilegeParams = `controller=BillingService&action=UpdateStatus`;
            DataServices.CheckPrivilege(privilegeParams).then(function (response) {
                if (response.data) {
                    var val = "";
                    $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(async function () {
                        if (val.length > 0) {
                            val += ',';
                        }
                        val += $(this).val();
                    });

                    vm.confirmR(vm.$t('AreYouSureToUpdateStatus'), true, false, function (result) {
                        var postJSON = {
                            Id: val || ID,
                            StatusId: StatusID,
                            TableName: "TALYGEN_BE_SERVICE_MASTER",
                            PrimaryColumn: "SERVICE_ID"
                        };
                        var objectPostString = JSON.stringify(postJSON);
                        locateBillingService.CommonUpdateStatus(objectPostString).then(async response => {
                            if (response.status == 200) {
                                vm.ShowAlert(vm.$t('RecordUpdatedSuccessfully'), "success", true, vm.$t("Alert"));
                                vm.FetchData();
                            }
                        });
                    })
                }
                else {
                    vm.ShowAlert(vm.$t('UnAuthorized'), "failure", vm.$t('Alert'));
                    return false;
                }
            });
        },
    }
}
</script>